import { BrowserRouter as Router, useRoutes } from 'react-router-dom';
import { routes } from './routeConfig';

function AppRoutes() {
    const element = useRoutes(routes);
    return element;
}

export default function App() {
    return (
        <Router>
            <AppRoutes />
        </Router>
    );
}
